import json, os, re

logs_dir = '/Users/leonid/workspace/open-station/artifacts/logs'
keywords = re.compile(r'Invalid transition|cannot transition|not allowed|openstation status|review.*in-progress|failed.*ready|backlog.*in-progress|in-progress.*backlog|review.*backlog|review.*ready', re.IGNORECASE)

for fname in sorted(os.listdir(logs_dir)):
    if not fname.endswith('.jsonl'):
        continue
    fpath = os.path.join(logs_dir, fname)
    with open(fpath) as f:
        for i, line in enumerate(f, 1):
            try:
                rec = json.loads(line)
            except:
                continue
            text_to_check = json.dumps(rec)
            if keywords.search(text_to_check):
                typ = rec.get('type', 'unknown')
                if typ == 'assistant':
                    contents = rec.get('message', {}).get('content', [])
                    for c in contents:
                        if c.get('type') == 'text' and keywords.search(c['text']):
                            print(f"[{fname}:{i}] ASSISTANT: {c['text'][:500]}")
                        elif c.get('type') == 'tool_use':
                            inp = json.dumps(c.get('input', {}))
                            if keywords.search(inp):
                                print(f"[{fname}:{i}] TOOL_USE({c.get('name','')}): {inp[:500]}")
                elif typ == 'user':
                    contents = rec.get('message', {}).get('content', [])
                    for c in contents:
                        if isinstance(c, dict) and c.get('type') == 'tool_result':
                            content_val = str(c.get('content', ''))
                            if keywords.search(content_val):
                                print(f"[{fname}:{i}] TOOL_RESULT: {content_val[:500]}")

