import json, os, re

logs_dir = '/Users/leonid/workspace/open-station/artifacts/logs'
keywords = re.compile(r'Invalid transition|cannot transition|not allowed|status.*error|error.*status|openstation status|review.*in-progress|failed.*ready|backlog.*in-progress|in-progress.*backlog|review.*backlog|review.*ready', re.IGNORECASE)

for fname in sorted(os.listdir(logs_dir)):
    if not fname.endswith('.jsonl'):
        continue
    fpath = os.path.join(logs_dir, fname)
    with open(fpath) as f:
        for i, line in enumerate(f, 1):
            try:
                rec = json.loads(line)
            except:
                continue
            # Check tool results for errors
            if rec.get('type') == 'tool_result' or rec.get('tool_use_result'):
                text = str(rec.get('tool_use_result', ''))
                if keywords.search(text):
                    print(f'{fname}:{i} TOOL_RESULT: {text[:300]}')
            # Check assistant text
            if rec.get('type') == 'assistant':
                contents = rec.get('message', {}).get('content', [])
                for c in contents:
                    if c.get('type') == 'text':
                        txt = c['text']
                        if keywords.search(txt):
                            print(f'{fname}:{i} ASSISTANT: {txt[:300]}')
                    elif c.get('type') == 'tool_use':
                        inp = json.dumps(c.get('input', {}))
                        if 'openstation status' in inp or 'status' in inp:
                            if keywords.search(inp):
                                print(f'{fname}:{i} TOOL_USE: {inp[:300]}')
"
